#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int x, y, xr, yr, D;
        scanf("%d %d %d %d %d", &x, &y, &xr, &yr, &D);
        int foodDays = x / xr;
        int waterDays = y / yr;
        int survive = foodDays < waterDays ? foodDays : waterDays;
        if (survive >= D) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

